WHERE o.region = #{region}
  AND s.region = #{region}

    AND s.merchant_id = #{query.merchantId}


    AND o.shop_id = #{query.shopId}


    AND o.user_id = #{query.userId}


    AND o.pay_status = #{query.payStatus}


    AND r.status = #{query.refundStatus}


    AND o.order_no = #{query.orderNo}


    AND o.created_at >= #{query.dateFrom}


    AND o.created_at < #{dateToExclusive}
